<script setup>
import { computed, onMounted, ref } from 'vue';
import { createApiClient, demoSnapshot, resolveAuthState } from './api/client.js';

const navItems = [{ key: 'overview', label: '经营总览', icon: '⌂' }, { key: 'products', label: '商品中心', icon: '▦' }, { key: 'purchases', label: '采购入库', icon: '↓' }, { key: 'sales', label: '销售出库', icon: '↑', badge: 1 }, { key: 'alerts', label: '库存预警', icon: '!' }, { key: 'movements', label: '库存流水', icon: '≋' }];
const activeNav = ref('overview'); const dataSource = ref('demo'); const toast = ref(''); const showLogin = ref(false); const loginError = ref(''); const loginForm = ref({ phone: '', password: '' }); const loginLoading = ref(false); const dashboard = ref({ ...demoSnapshot.dashboard }); const products = ref([...demoSnapshot.products]); const warehouses = ref([...demoSnapshot.warehouses]); const alerts = ref([...demoSnapshot.alerts]); const purchases = ref([...demoSnapshot.purchases]); const sales = ref([...demoSnapshot.sales]); const movements = ref([...demoSnapshot.movements]); const client = createApiClient({ token: typeof window !== 'undefined' ? window.localStorage.getItem('stockflow_access_token') || '' : '' });
const authState = ref(resolveAuthState({ baseUrl: client.isConfigured() ? 'configured' : '', token: client.getToken() }));
const pageTitle = computed(() => navItems.find((item) => item.key === activeNav.value)?.label || '经营总览'); const sourceLabel = computed(() => dataSource.value === 'api' ? '实时接口' : '演示数据'); const pendingInbound = computed(() => purchases.value.filter((item) => item.status === '待入库').length); const pendingOutbound = computed(() => sales.value.filter((item) => item.status === '待发货').length); const money = (value) => `¥${Number(value || 0).toLocaleString('zh-CN')}`;

async function loadData() { const results = await Promise.all([client.dashboard(), client.products(), client.warehouses(), client.alerts(), client.purchases(), client.sales(), client.movements()]); dataSource.value = results.every((item) => item.source === 'api') ? 'api' : 'demo'; dashboard.value = { ...dashboard.value, ...results[0].data }; products.value = results[1].data.list || []; warehouses.value = results[2].data.list || []; alerts.value = results[3].data.list || []; purchases.value = results[4].data.list || []; sales.value = results[5].data.list || []; movements.value = results[6].data.list || []; }
function setNav(key) { activeNav.value = key; }
function flash(text) { toast.value = text; window.setTimeout(() => { toast.value = ''; }, 2200); }
async function completePurchase(order) { const result = await client.receivePurchase(order.id); purchases.value = purchases.value.map((item) => item.id === order.id ? { ...item, ...(result.data || result) , status: '已入库' } : item); flash(`${order.id} 已确认入库`); }
async function completeSale(order) { const result = await client.shipSale(order.id); sales.value = sales.value.map((item) => item.id === order.id ? { ...item, ...(result.data || result), status: '已完成' } : item); flash(`${order.id} 已确认出库`); }
async function submitLogin() { loginError.value = ''; loginLoading.value = true; try { await client.login(loginForm.value); authState.value = 'authenticated'; await loadData(); } catch (error) { loginError.value = error instanceof Error ? error.message : '登录失败'; } finally { loginLoading.value = false; } }
function enterDemo() { authState.value = 'offline-demo'; dataSource.value = 'demo'; }
async function logout() { await client.logout(); authState.value = client.isConfigured() ? 'login' : 'offline-ready'; }
onMounted(() => { if (authState.value === 'authenticated' || authState.value === 'offline-ready') loadData(); });
</script>

<template>
  <section v-if="!['authenticated', 'offline-demo'].includes(authState)" class="auth-shell"><div class="auth-card"><div class="brand brand--auth"><span class="brand-mark">▦</span><div><strong>StockFlow</strong><small>进销存运营中心</small></div></div><p class="eyebrow">STOCK FLOW ADMIN · OPEN SOURCE</p><h1>让库存流动，<br />让经营更清晰</h1><p class="auth-description">免费、开源、可自部署的商品与库存管理后台。先用演示数据体验完整工作台。</p><form v-if="authState === 'login'" class="auth-form" @submit.prevent="submitLogin"><label>管理员手机号<input v-model="loginForm.phone" type="tel" placeholder="13900000000" /></label><label>密码<input v-model="loginForm.password" type="password" placeholder="demo123456" /></label><p v-if="loginError" class="auth-error">{{ loginError }}</p><button class="primary-button" type="submit" :disabled="loginLoading">{{ loginLoading ? '登录中…' : '进入运营中心' }}　→</button><button class="text-button" type="button" @click="enterDemo">暂不登录，进入离线演示</button></form><div v-else class="offline-panel"><strong>离线演示已准备好</strong><p>使用本地虚构数据，不会向服务器发送请求。</p><button class="primary-button" type="button" @click="enterDemo">查看工作台　→</button></div><p class="auth-foot"><i></i>{{ client.isConfigured() ? '已配置 StockFlow API' : '未配置 API · 可直接预览' }}</p></div></section>
  <div v-else class="app-shell"><aside class="sidebar"><div class="brand"><span class="brand-mark">▦</span><div><strong>StockFlow</strong><small>库存运营中心</small></div></div><div class="workspace"><span></span>东城中心仓 <b>⌄</b></div><p class="nav-caption">工作台</p><nav><button v-for="item in navItems" :key="item.key" class="nav-item" :class="{ active: activeNav === item.key }" @click="setNav(item.key)"><span class="nav-icon">{{ item.icon }}</span>{{ item.label }}<em v-if="item.badge && pendingOutbound">{{ pendingOutbound }}</em></button></nav><div class="sidebar-footer"><div class="mini-avatar">许</div><div><strong>许汝林</strong><small>超级管理员</small></div><button class="logout" @click="logout">↪</button></div></aside><main class="main-content"><header class="topbar"><div>工作台　/　<strong>{{ pageTitle }}</strong></div><div class="topbar-right">2026 年 7 月 16 日 · 星期四 <span class="source-badge">{{ sourceLabel }}</span></div></header><section class="page-heading"><div><p class="eyebrow">THURSDAY, JUL 16 · STOCKFLOW</p><h1>{{ pageTitle }} <span>✦</span></h1><p class="heading-copy">今天有 <strong>{{ pendingInbound }} 笔采购待入库</strong>、<strong>{{ pendingOutbound }} 笔销售待出库</strong>。<span class="source-badge">{{ sourceLabel }}</span></p></div><button class="primary-button" @click="setNav('purchases')">＋ 新建采购单</button></section><section class="metric-grid"><article class="metric-card metric-card--dark"><span>今日销售</span><strong>{{ money(dashboard.todaySales) }}</strong><small>↗ 较昨日 +12.8%</small></article><article class="metric-card"><span>库存总值</span><strong>{{ money(dashboard.stockValue) }}</strong><small class="blue">{{ warehouses.length }} 个仓库</small></article><article class="metric-card"><span>待入库</span><strong>{{ dashboard.pendingInbound }}<small> 笔</small></strong><small class="orange">需要及时收货</small></article><article class="metric-card metric-card--warning"><span>低库存</span><strong>{{ dashboard.lowStock }}<small> 项</small></strong><small class="danger">建议今日补货</small></article></section><section v-if="activeNav === 'overview'" class="content-grid"><article class="panel"><div class="panel-heading"><div><h2>库存预警</h2><p>低于 SKU 安全库存的商品</p></div><button class="link-button" @click="setNav('alerts')">查看全部 →</button></div><div class="alert-row" v-for="item in alerts" :key="item.productId"><span class="alert-icon" :class="item.severity">!</span><div><strong>{{ item.name }}</strong><small>{{ item.warehouse }} · {{ item.sku }}</small></div><b :class="item.severity">{{ item.stock }}<small>/{{ item.minStock }}</small></b></div></article><article class="panel"><div class="panel-heading"><div><h2>仓库概览</h2><p>各仓库 SKU 数量</p></div><button class="link-button" @click="setNav('products')">商品明细 →</button></div><div class="warehouse-row" v-for="item in warehouses" :key="item.id"><span class="warehouse-icon">⌂</span><div><strong>{{ item.name }}</strong><small>{{ item.address }}</small></div><b>{{ item.stockKeep }}<small> SKU</small></b></div></article></section><section v-else-if="activeNav === 'products' || activeNav === 'alerts'" class="panel full-panel"><div class="panel-heading"><div><h2>{{ activeNav === 'products' ? '商品中心' : '库存预警' }}</h2><p>{{ activeNav === 'products' ? '商品、SKU 与安全库存' : '需要优先补货的商品' }}</p></div></div><div class="table"><div class="table-head"><span>商品</span><span>仓库</span><span>当前库存</span><span>状态</span></div><div v-for="item in activeNav === 'products' ? products : alerts" :key="item.id || item.productId" class="table-row"><span><strong>{{ item.name }}</strong><small>{{ item.sku }}</small></span><span>{{ item.warehouse }}</span><span>{{ item.stock }} / {{ item.minStock }}</span><span class="status" :class="item.status || item.severity">{{ item.status === 'normal' ? '库存正常' : item.status === 'danger' || item.severity === 'danger' ? '严重预警' : item.status === 'warning' || item.severity === 'warning' ? '库存偏低' : item.status }}</span></div></div></section><section v-else class="panel full-panel"><div class="panel-heading"><div><h2>{{ activeNav === 'purchases' ? '采购入库' : activeNav === 'sales' ? '销售出库' : '库存流水' }}</h2><p>单据动作可回退到演示数据</p></div></div><div v-if="activeNav === 'purchases'" class="table"><div class="table-head"><span>采购单</span><span>供应商</span><span>金额</span><span>动作</span></div><div v-for="item in purchases" :key="item.id" class="table-row"><span><strong>{{ item.id }}</strong><small>{{ item.warehouse }}</small></span><span>{{ item.supplier }}</span><span>{{ money(item.amount) }}</span><span><button v-if="item.status === '待入库'" class="action-button" @click="completePurchase(item)">确认入库</button><span v-else class="status success">已入库</span></span></div></div><div v-else-if="activeNav === 'sales'" class="table"><div class="table-head"><span>销售单</span><span>客户</span><span>金额</span><span>动作</span></div><div v-for="item in sales" :key="item.id" class="table-row"><span><strong>{{ item.id }}</strong><small>{{ item.warehouse }}</small></span><span>{{ item.customer }}</span><span>{{ money(item.amount) }}</span><span><button v-if="item.status === '待发货'" class="action-button" @click="completeSale(item)">确认出库</button><span v-else class="status success">已完成</span></span></div></div><div v-else class="table"><div class="table-head"><span>商品</span><span>仓库</span><span>类型</span><span>数量</span></div><div v-for="item in movements" :key="item.id" class="table-row"><span><strong>{{ item.product }}</strong><small>{{ item.source }}</small></span><span>{{ item.warehouse }}</span><span class="status" :class="item.type === '入库' ? 'success' : 'warning'">{{ item.type }}</span><span :class="item.type === '入库' ? 'in-number' : 'out-number'">{{ item.type === '入库' ? '+' : '-' }}{{ item.quantity }}</span></div></div></section><footer>StockFlow 进销存运营中心 · 免费开源 · MySQL 8.4 + Redis 8</footer></main><div v-if="toast" class="toast">{{ toast }}</div></div>
</template>
